"use client"

import { useState } from "react"
import {
  Menu,
  X,
  LogOut,
  Home,
  Database,
  TrendingUp,
  Gauge,
  Target,
  Settings,
  LifeBuoy as Lifebuoy,
  ChevronLeft,
  ChevronRight,
  Building2,
  Users,
  User,
  Briefcase,
  UserCog,
} from "lucide-react"
import { Button } from "@/components/ui/button"
import Link from "next/link"
import Image from "next/image"
import { usePathname } from "next/navigation"
import { useAuth } from "@/lib/auth-context"

interface SidebarProps {
  isOpen: boolean
  setIsOpen: (isOpen: boolean) => void
}

export function Sidebar({ isOpen, setIsOpen }: SidebarProps) {
  const [isMobileOpen, setIsMobileOpen] = useState(false)
  const { userProfile, logout } = useAuth()
  const pathname = usePathname()

  interface NavItem {
    icon?: any
    label?: string
    href?: string
    header?: string
  }

  const navItems: NavItem[] = [
    { icon: Home, label: "Dashboard", href: "/" },
    { icon: Database, label: "Data Inputs", href: "/data-inputs" },
    { icon: Target, label: "Gross Profit Target", href: "/gross-profit-target" },
    { icon: TrendingUp, label: "Simulator", href: "/simulator" },
    { icon: Gauge, label: "Efficiency Analysis", href: "/efficiency-analysis" },
    // Settings Section
    { header: "SETTINGS" },
    //{ icon: Building2, label: "Branch Settings", href: "/settings/branch" },
    //{ icon: Briefcase, label: "Company Settings", href: "/settings/company" },
    //{ icon: Users, label: "Company Users", href: "/settings/users" },
    //{ icon: UserCog, label: "My Settings", href: "/settings/profile" },
    { icon: Building2, label: "Branch Settings", href: "#" },
    { icon: Briefcase, label: "Company Settings", href: "#" },
    { icon: Users, label: "Company Users", href: "#" },
    { icon: UserCog, label: "My Settings", href: "#" },

  ]

  // Get user initials for avatar
  const getUserInitials = () => {
    if (!userProfile) return "U"
    return `${userProfile.firstName.charAt(0)}${userProfile.lastName.charAt(0)}`.toUpperCase()
  }

  // Get user display name
  const getUserDisplayName = () => {
    if (!userProfile) return "User"
    return `${userProfile.firstName} ${userProfile.lastName}`
  }

  return (
    <>
      {/* Mobile toggle */}
      <Button
        variant="ghost"
        size="icon"
        className="lg:hidden fixed top-4 left-4 z-40"
        onClick={() => setIsMobileOpen(!isMobileOpen)}
      >
        {isMobileOpen ? <X className="w-5 h-5" /> : <Menu className="w-5 h-5" />}
      </Button>

      {/* Sidebar */}
      <aside
        className={`fixed left-0 top-0 h-screen bg-sidebar border-r border-sidebar-border transition-all duration-300 ease-in-out z-30 flex flex-col overflow-hidden shadow-xl backdrop-blur-xl
          ${isOpen ? "w-64" : "w-0"} 
          ${isMobileOpen ? "translate-x-0" : "-translate-x-full"} lg:translate-x-0`}
      >
        {/* Header */}
        <div className="p-6 border-b border-sidebar-border flex-shrink-0 bg-sidebar/50 backdrop-blur-sm">
          <div className="flex items-center justify-between">
            <div className={`flex items-center gap-3 transition-opacity duration-200 ${isOpen ? 'opacity-100' : 'opacity-0'}`}>
              <div className="relative w-40 h-10 rounded-lg overflow-hidden">
                <Image
                  src="/logo for light screen.png"
                  alt="MarginPilot Logo"
                  fill
                  className="object-contain dark:hidden"
                />
                <Image
                  src="/logo for dark screen.png"
                  alt="MarginPilot Logo"
                  fill
                  className="object-contain hidden dark:block"
                />
              </div>

            </div>

            {/* Desktop Toggle Button */}
            <Button
              variant="ghost"
              size="icon"
              onClick={() => setIsOpen(!isOpen)}
              className="hidden lg:flex h-6 w-6"
            >
              {isOpen ? (
                <ChevronLeft className="w-4 h-4" />
              ) : (
                <ChevronRight className="w-4 h-4" />
              )}
            </Button>
          </div>
        </div>

        {/* Navigation */}
        <nav className="flex-1 p-4 space-y-2 overflow-y-auto">
          {navItems.map((item, index) => {
            // Handle section headers
            if (item.header) {
              return (
                <div key={index} className="px-3 py-2 text-xs font-semibold text-sidebar-foreground/50 uppercase tracking-wider">
                  {item.header}
                </div>
              )
            }

            // Handle navigation items
            const { icon: Icon, label, href } = item
            if (!Icon || !label || !href) return null

            const isActive = pathname === href;

            return (
              <Link key={label} href={href}>
                <Button
                  variant="ghost"
                  className={`
                    w-full justify-start gap-3 rounded-lg transition-all duration-200 group
                    ${isActive
                      ? 'bg-primary text-primary-foreground shadow-lg shadow-primary/20 hover:bg-primary/90'
                      : 'text-sidebar-foreground/70 hover:text-sidebar-foreground hover:bg-sidebar-accent dark:hover:bg-sidebar-accent/20'
                    }
                    ${isOpen ? 'px-3' : 'px-2'}
                  `}
                >
                  <Icon className={`h-5 w-5 mr-3 transition-colors ${isActive ? 'text-primary-foreground' : 'text-sidebar-foreground/60 group-hover:text-primary'}`} />
                  <span className={`text-sm transition-all duration-200 ${isOpen ? 'opacity-100 max-w-32' : 'opacity-0 max-w-0 overflow-hidden'}`}>
                    {label}
                  </span>
                </Button>
              </Link>
            )
          })}
        </nav>

        {/* Footer */}
        <div className={`p-4 border-t border-sidebar-border space-y-3 transition-all duration-200 bg-sidebar/50 backdrop-blur-sm ${isOpen ? 'opacity-100' : 'opacity-0'}`}>
          <div className="flex items-center gap-3 px-2">
            <div className="w-8 h-8 rounded-full bg-primary/20 dark:bg-primary/30 flex items-center justify-center ring-2 ring-primary/10">
              <span className="text-xs font-bold text-primary dark:text-primary">{getUserInitials()}</span>
            </div>
            <div className="flex-1 min-w-0">
              <p className="text-xs font-medium text-sidebar-foreground truncate">{getUserDisplayName()}</p>
              <p className="text-xs text-sidebar-foreground/60 truncate">{userProfile?.company.name || "Owner"}</p>
            </div>
          </div>
          <Button
            variant="outline"
            className="w-full text-sidebar-foreground/70 hover:text-sidebar-foreground hover:bg-sidebar-accent dark:hover:bg-sidebar-accent/20 justify-start gap-2 text-xs bg-transparent border-sidebar-border"
            onClick={logout}
          >
            <LogOut className="w-4 h-4" />
            Log Out
          </Button>
        </div>
      </aside>

      {/* Overlay for mobile */}
      {isMobileOpen && <div className="fixed inset-0 bg-black/50 z-20 lg:hidden" onClick={() => setIsMobileOpen(false)} />}
    </>
  )
}
