"use client"

import { useState } from "react"
import { Sidebar } from "@/components/sidebar"
import { TopHeader } from "@/components/top-header"
import { ChevronRight } from "lucide-react"
import { Button } from "@/components/ui/button"

export default function DashboardLayout({
  children,
}: Readonly<{
  children: React.ReactNode
}>) {
  const [isSidebarOpen, setIsSidebarOpen] = useState(true)

  return (
    <div className="min-h-screen bg-background flex">
      {/* Sidebar */}
      <Sidebar isOpen={isSidebarOpen} setIsOpen={setIsSidebarOpen} />

      {/* Main Content Area */}
      <div
        className={`flex-1 transition-all duration-300 ease-in-out ${
          isSidebarOpen ? "lg:ml-64" : "lg:ml-0"
        }`}
      >
        {/* Top Header */}
        <div className="sticky top-0 z-40 bg-background">
          <TopHeader isSidebarOpen={isSidebarOpen} />

          {/* Desktop Sidebar Open Button (only when closed) */}
          {!isSidebarOpen && (
            <div className="hidden lg:block fixed left-4 top-20 z-30">
              <Button
                variant="ghost"
                size="icon"
                onClick={() => setIsSidebarOpen(true)}
                className="h-8 w-8 rounded-full shadow-lg bg-card/80 backdrop-blur-sm border border-border/50 transition-colors duration-200  "
              >
                <ChevronRight className="w-4 h-4" />
              </Button>
            </div>
          )}
        </div>

        {/* Main Content */}
        <main className="p-6 pt-20 z-10 relative transition-all duration-300 ease-in-out">
          {children}
        </main>
      </div>
    </div>
  )
}
